    10|export async function sendWhatsApp(to: string, message: string): Promise<boolean> {
    11|  const number = cleanNumber(to)
    12|  try {
    13|    const res = await fetch(
    14|      `${EVOLUTION_URL}/message/sendText/${EVOLUTION_INSTANCE}`,
    15|      {
    16|        method: 'POST',
    17|        headers: {
    18|          'Content-Type': 'application/json',
    19|          'apikey': EVOLUTION_API_KEY,
    20|        },
    21|        body: JSON.stringify({
    22|          number,
    23|          text: message,
