     9|export function AnalyticsProvider() {
    10|  const pathname = usePathname()
    11|
    12|  useEffect(() => {
    13|    if (!GA_MEASUREMENT_ID) return
    14|
    15|    const gtag = (...args: unknown[]) => {
    16|      const w = window as unknown as { dataLayer?: unknown[] }
    17|      w.dataLayer = w.dataLayer || []
    18|      w.dataLayer.push(args)
    19|    }
    20|    gtag("js", new Date())
    21|    gtag("config", GA_MEASUREMENT_ID, {
    22|      page_path: pathname,
    23|    })
    24|    // eslint-disable-next-line react-hooks/exhaustive-deps
    25|  }, [pathname])
    26|
    27|  if (!GA_MEASUREMENT_ID) return null
    28|
    29|  return (
    30|    <>
    31|      <Script
    32|        src={`https://www.googletagmanager.com/gtag/js?id=${GA_MEASUREMENT_ID}`}
    33|        strategy="afterInteractive"
